def assign_frequencies(n, k, edges, fixed):
    adj = [set() for _ in range(n)]
    for u, v in edges:
        adj[u].add(v)
        adj[v].add(u)

    assignment = [0] * n

    # Apply fixed assignments and validate range
    for node, freq in fixed.items():
        if freq < 1 or freq > k:
            return [-1]
        assignment[node] = freq

    # Check fixed-fixed conflicts on edges
    for u, v in edges:
        if u in fixed and v in fixed and fixed[u] == fixed[v]:
            return [-1]

    def is_valid(node, freq):
        for neighbor in adj[node]:
            if assignment[neighbor] == freq:
                return False
        return True

    def backtrack(node):
        if node == n:
            return True
        if node in fixed:
            # Already assigned; just verify consistency and proceed
            if is_valid(node, assignment[node]):
                return backtrack(node + 1)
            else:
                return False
        for freq in range(1, k + 1):
            if is_valid(node, freq):
                assignment[node] = freq
                if backtrack(node + 1):
                    return True
                assignment[node] = 0
        return False

    if backtrack(0):
        return assignment
    else:
        return [-1]

